async function seed() {
  const payload = await getPayload({ config: configPromise })
  console.log('🌱 Seeding events...')

  for (const event of events) {
    try {
      const existing = await payload.find({
        collection: 'events',
        where: { slug: { equals: event.slug } },
        limit: 1,
      })

      if (existing.docs.length > 0) {
        console.log(`⏭️  Skipping "${event.title}" — already exists`)
        continue
      }

      const { description, endDate, ...rest } = event

      await payload.create({
        collection: 'events',
        data: {
          ...rest,
          ...(endDate ? { endDate } : {}),
          description: toRichText(description),
        },
      })

      console.log(`✅ Created "${event.title}"`)
    } catch (err) {
      console.error(`❌ Failed "${event.title}":`, err)
    }
  }

  console.log('✅ Done seeding events')
  process.exit(0)
}

